INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (476,2,9,3,1,'FUNCIÓN DE CUIDADO|1.  ¿Qué  hacen  cuando  un  niño,  niña  o adolescente de su hogar se enferma? ¿Por lo general, van al Centro de Salud?|SÍ: Buscan ayuda profesional en la posta o centro de salud, hospital. NO: Es atendido en casa.
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (477,2,9,3,2,'FUNCIÓN DE CUIDADO|2.  ¿Los/as  NNA  asisten  a  la  escuela  de forma regular?|SÍ: Están matriculados, asisten normalmente
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (478,2,9,3,3,'FUNCIÓN DE CUIDADO|3.   ¿El/la   cuidador/a   principal  apoya  y/o monitorea  las tareas escolares en casa, al menos  3  días  de  la  semana?  ¿De  qué manera?|SÍ:  La  respuesta  es  positiva,  miran  juntos  las  tareas,  le ayuda con materiales, algún dibujo, le hace dictado, le toma la lección, leen juntos, busco apoyo en otra persona. etc.
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (479,2,9,3,4,'FUNCIÓN DE CUIDADO|4.  ¿NNA  reciben  como mínimo 3 comidas al día?|SÍ: Recibe 3 comidas y toma desayuno como primera comida.
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (480,2,9,3,5,'FUNCIÓN DE CUIDADO|5.  Cuando usted no puede encargarse del cuidado de sus hijos o NNA a cargo ¿Qué pasa con ellos?| SÍ: Hay un/a adulto/a dentro de la casa cuando están los/as NNA en ella.
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (481,2,9,3,6,'FUNCIÓN DE CUIDADO|6. ¿Qué hacen cuando otra persona adulta de  su  familia  cercana  se  enferma?  Por lo general, van a…|SÍ: Buscan ayuda profesional en la posta o centro de salud, hospital.
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (482,2,9,3,7,'FUNCIÓN DE CUIDADO|7.   ¿En   su   familia   hay  algún  NNA  con discapacidad?  ¿de qué tipo?|NO:  No hay NNA con discapacidad en la familia
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (483,2,9,3,8,'FUNCIÓN DE CUIDADO|8. ¿Quién atiende, acompaña, ayuda (le da sus  medicinas  si  es  el  caso)  al  NNA  con discapacidad?|SÍ:  Algún  miembro  de  la  familia lo cuida mayormente, tiene su propio cuidador diferente del cuidador del niño evaluado.
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (484,2,9,3,9,'SUB TOTAL FUNCIÓN DE CUIDADO', SYSDATE, NULL, 0);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (485,2,9,4,1,'FUNCIÓN FORMADORA|9.   ¿Reconoce   cuando   sus   NNA   están tristes,   molestos   o   cuando   algo   le   ha pasado,  aunque  no  lo  digan?  ¿en  qué  lo nota?|SÍ: Sí, porque cambia algo en él/ella (aunque no lo especifique), lo nota en que está callado/a, apagado/a, sin apetito, con otra cara, cansado/a, etc.
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (486,2,9,4,2,'FUNCIÓN FORMADORA|10. ¿El niño o niña juega todos los días con alguno  de  los/as  adultos/as,  al  menos  15 minutos diarios? ¿A qué juegan?|SÍ:   Hay un momento en que solo se dedican a jugar con el/la niño/a. Menciona dos juegos o describe dos interacciones de juego.
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (487,2,9,4,3,'FUNCIÓN FORMADORA|11.  ¿Felicita  o reconoce, premia, al niño o niña   cuando   algo   le   salió   muy   bien?
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (488,2,9,4,4,'FUNCIÓN FORMADORA|12.  ¿De  qué  manera  les  corrigen  cuando ha habido un mal comportamiento?
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (489,2,9,4,5,'FUNCIÓN FORMADORA|13.   ¿Qué   hace   con   la   opinión  de  sus hijos/as o NNA? Usted…
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (490,2,9,4,6,'FUNCIÓN FORMADORA|14.   ¿Hay  normas  de  convivencia  en  tu casa?
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (491,2,9,4,7,'FUNCIÓN FORMADORA|15.   ¿Quién   o   quiénes   determinan   las normas de convivencia en tu casa?|SÍ: todos los integrantes del hogar participamos
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (492,2,9,4,8,'SUB TOTAL FUNCIÓN FORMADORA', SYSDATE, NULL, 0);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (493,2,9,5,1,'FUNCIÓN AFECTIVA|16. ¿Creció usted en una familia cariñosa? A  las  personas  que  cuidaban  de  usted,
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (494,2,9,5,2,'FUNCIÓN AFECTIVA|17.    Expresa    afecto    físicamente    con abrazos,  besos  y  caricias a sus hijos/as o NNA a cargo?|SÍ: De manera espontánea o en respuesta a sus muestras de afecto
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (495,2,9,5,3,'FUNCIÓN AFECTIVA|18.  ¿Expresa  amabilidad  y  afecto  a  otros miembros  de  su  familia  (abuela/o,  tío/a, sobrinos/as,   suegro/a,   que   no   sean   su pareja o hijos/as?|SÍ: De manera espontánea o en respuesta a sus muestras de afecto
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (496,2,9,5,4,'FUNCIÓN AFECTIVA|19.   ¿Busca   apoyo   en   su   familia   ante situaciones    de    peligro    o    situaciones difíciles?|SÍ: Los/as miembros de la familia están dispuestos a apoyarse mutuamente.
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (497,2,9,5,5,'FUNCIÓN AFECTIVA|20.  Ante  alguna  situación  de  peligro  ¿se siente  protegido/a  y  respaldado/a  por  su entorno familiar?|SÍ: siento que los integrantes de mi familia se preocupan por mí.
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (498,2,9,5,6,'FUNCIÓN AFECTIVA|21.  ¿Qué  hace  cuando  su hijo/a o NNA a cargo     le     cuenta     un     problema     o preocupación?|SÍ: siento que los integrantes de mi familia se preocupan por mí.
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (499,2,9,5,7,'FUNCIÓN AFECTIVA|21.  ¿Qué  hace  cuando  su hijo/a o NNA a cargo     le     cuenta     un     problema     o preocupación?|SÍ: Lo/a escucho, a fin de comprender la situación, le brindo un consejo o busco ayuda profesional.
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (500,2,9,5,8,'FUNCIÓN AFECTIVA|22. ¿Usted es capaz de calmar el miedo, la frustración,  la  cólera  del/la  NNA?  ¿Logra consolarlo/a? ¿Qué hace?|SÍ:  Con  su  presencia,  palabras  o  actitud,  puede consolar al/la NNA. El/la NNA lo/la busca para que lo/la consuele o proteja.
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (501,2,9,5,9,'FUNCIÓN AFECTIVA|23.  ¿A  quién  recurren los/as NNA cuando tienen un dolor o un problema, o si está en peligro?|SÍ: NNA busca al/la cuidador/a principal o al padre/madre.
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (502,2,9,6,1,'24. ¿Los/as NNA visitan a sus familiares?|SÍ:  La  familia, incluidos los/as NNA van a casa de abuelos/as, o tíos/as que no viven con ellos. Puede ser por fechas especiales.
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (503,2,9,6,2,'FUNCIÓN SOCIALIZADORA|25.  En  relación  con  los  acuerdos  que  se toman en su comunidad, la familia.|SÍ: Participa y colabora.
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (504,2,9,6,3,'FUNCIÓN SOCIALIZADORA|26.   Con   sus   familiares   ¿existen   viejas rencillas, disgustos antiguos, conflictos que no  se  han  resuelto  aún,  pese  a  no  vivir juntos?|SÍ: Hay viejos problemas, la familia y sus familiares no se llevan bien o no se hablan entre algunos, similar.
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (505,2,9,6,4,'SUB TOTAL FUNCIÓN SOCIALIZADORA', SYSDATE, NULL, 0);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (506,2,9,7,1,'27.  ¿padre,  madre  o  tutor de la familia se encuentra desempleado?|SÍ
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (507,2,9,7,2,'FUNCIÓN DE SEGURIDAD ECONÓMICA|28.  En  su  familia  ¿Tienen  costumbre  de ahorrar?
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (508,2,9,7,3,'FUNCIÓN DE SEGURIDAD ECONÓMICA|29.  ¿En  qué se utiliza el dinero ahorrado?
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (509,2,9,7,4,'FUNCIÓN DE SEGURIDAD ECONÓMICA|30. ¿Los/as NNA de 5 años a más, saben, conocen dónde y en qué trabaja la persona adulta    que    trae    el    dinero    para    su manutención?|SÍ:  NNA  conoce  a qué se dedica papá o mamá. Al menos de nombre conocen dónde.
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (510,2,9,7,5,'SUB TOTAL FUNCIÓN DE SEGURIDAD ECONÓMICA', SYSDATE, NULL, 0);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (511,2,9,8,1,'RELACIONES DE PAREJA|31. Cuando empezó la convivencia con su pareja actual. ¿qué edad tenían?|SÍ: Ambos mayores de edad
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (512,2,9,8,2,'RELACIONES DE PAREJA|32.   ¿Su   compañero/a   o   conviviente,   le muestra   afecto,   cariño,   le  da  atención?
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (513,2,9,8,3,'RELACIONES DE PAREJA|33. En su relación de pareja ¿Quién decide sobre utilizar alguna forma para cuidarse y no tener hijos/as?|SÍ: Ambos
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (514,2,9,8,4,'RELACIONES DE PAREJA|34. En su relación de pareja ¿Quién decide cómo   se   debe   gastar   el   dinero   en   la familia?|SÍ: Ambos
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (515,2,9,8,5,'RELACIONES DE PAREJA|35.  En  general,  cuando  en  el  hogar  hay que tomar una decisión que afecta a los/as hijos/as, ustedes suelen…|SÍ: Conversar y ponerse de acuerdo
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (516,2,9,8,6,'RELACIONES DE PAREJA|36.  Las parejas tienen diferencias a veces
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (517,2,9,8,7,'RELACIONES DE PAREJA|37. ¿Por qué motivo surgen los conflictos?|SÍ: Por desacuerdos que luego se pueden afrontar.
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (518,2,9,8,8,'SUB TOTAL RELACIONES DE PAREJA', SYSDATE, NULL, 0);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (519,2,9,9,1,'RELACIONES PARENTALES|38. ¿Cómo se divide el trabajo en la casa, incluyendo los/as NNA?|SÍ:  Se  turnan,  hay  relativa  equidad  en  las  tareas  de  casa. Todos tiene alguna tarea.
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (520,2,9,9,2,'RELACIONES PARENTALES|39. ¿Qué cosas hacen juntos, todos/as, en familia?
(faenas   y   actividades  de  la  comunidad, jugar,  arreglar  la  casa,  cuidar  juntos a los animales, asistir a su iglesia, viajar, otro.)|SÍ: Al menos dos de las mencionados o similares. NO: Nada o solo una.
(Esperar a que cuidador principal proponga)', SYSDATE, NULL, 0);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (521,2,9,9,3,'RELACIONES PARENTALES|40.   ¿Sus   hijos/as   o   NNA   a   cargo   les cuentan sobre las cosas que le gustan, sus intereses o temas que a ellos les agradan?|SÍ: Me cuentan sus gustos o intereses
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (522,2,9,9,4,'RELACIONES PARENTALES|41.   ¿Sus   hijos/as   o   NNA   a   cargo   les cuentan  sus  problemas  y  preocupaciones personales?|SÍ:  Cada  cosa  que  les  molesta.  Me  cuentan  algunas  cosas,  no  todas, pero la mayoría.
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (523,2,9,9,5,'SUB TOTAL RELACIONES PARENTALES', SYSDATE, NULL, 0);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (524,2,9,10,1,'42.  ¿Hay  alguna  persona en el hogar que es adulto/a mayor?|SÍ: Abuelos/as, tíos/as mayores de 65 y que viven allí. NO: No hay nadie.', SYSDATE, NULL, 0);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (525,2,9,10,2,'RELACIONES ENTRE PARIENTES|43.   ¿Hay   alguna   persona   adulta   que requiere  atención  especial?  ¿Quién  la/lo cuida?|SÍ:  Cualquier  persona  adulta  de  la familia que tenga que medicarse y necesita algún tipo de cuidado. Lo/a cuida el/la cuidador/a principal o un familiar directo o se busca ayuda para su cuidado.
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (526,2,9,10,3,'RELACIONES ENTRE PARIENTES|44.   ¿Hay   alguna   persona,   amigo/a,   o familiar,  que  visita  su  casa  para  consumir alcohol o drogas?|SÍ:   Familiares   o   amigos/as   que   frecuentan   y   beben   en   la   casa   hasta emborracharse o quedarse dormidos/as.
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (527,2,9,10,4,'RELACIONES ENTRE PARIENTES|45. ¿Hay una persona que vive en la casa, que   cuando   consume   alcohol  o  drogas cambia  mucho?  ¿Se  pone  agresivo/a  con las personas o las cosas?|SÍ:  rompe  las  cosas,  su  conducta  se  torna  agresiva  (violencia  en  todas  sus modalidades), tiene conductas de acoso u hostigamiento sexual.
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (528,2,9,10,5,'RELACIONES ENTRE PARIENTES|46.  El  último  mes,  usted  ¿se  siente  muy cansada/o?  ¿Le  duele  la  cabeza?  o  ¿No duerme   bien?   ¿Algún   dolor   o   fiebres?
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (529,2,9,10,6,'RELACIONES ENTRE PARIENTES|47.  ¿A  algún  integrante  del  hogar,  le  han hecho sentir vergüenza en su casa o en su comunidad?|SÍ:  Puede  asentir  con  la  cabeza,  bajar  la  cabeza,  sonrojarse  o  responder  ""sí, señorita/joven"", ""tal vez"", ""alguna vez"". En tal caso, preguntar: ¿Dónde? ¿Con su compañero/a?  ¿Con  el/la  doctor/a? ¿En una reunión? Si no quiere profundizar, no se insiste.
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (530,2,9,10,7,'SUB TOTAL RELACIONES ENTRE PARIENTES', SYSDATE, NULL, 0);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (531,2,9,11,1,'ENTORNO COMUNITARIO LIBRE DE VIOLENCIA|48.   ¿Alguien  de  su  familia  pertenece  o participa activamente en las decisiones que se toman en la comunidad?|SÍ: Es parte de la asamblea, o asiste siempre.
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (532,2,9,11,2,'ENTORNO COMUNITARIO LIBRE DE VIOLENCIA|49.    ¿Su    familia    es    conocida    en   su comunidad?     ¿Por     alguna     razón    en particular?|SÍ:  Los  reconocen por ser una familia antigua, por haber sido autoridad, por su participación, por ser buenos/as vecinos/as, ayudaron o son ayudados/as.
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (533,2,9,11,3,'ENTORNO COMUNITARIO LIBRE DE VIOLENCIA|50.   ¿Hay   algunas   actividades   para   las familias en la comunidad?|SÍ:  Hay  fiesta  o  actividades  convocadas  por  algún  sector,  municipalidad  o  la comunidad misma.
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (534,2,9,11,4,'SUB TOTAL ENTORNO COMUNITARIO LIBRE DE VIOLENCIA', SYSDATE, NULL, 0);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (535,2,9,12,1,'ENTORNO COMUNITARIO QUE PROMUEVE EJERCICIO DE DERECHOS|51. ¿Se habla en su comunidad sobre la violencia en las familias? ¿En qué espacio?
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (536,2,9,12,2,'ENTORNO COMUNITARIO QUE PROMUEVE EJERCICIO DE DERECHOS|52. ¿Cuál de estos servicios o programas conoce usted?
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (537,2,9,12,3,'ENTORNO COMUNITARIO QUE PROMUEVE EJERCICIO DE DERECHOS|53.  ¿A  qué  servicios  se  puede recurrir en caso de violencia?|SÍ: Menciona cualquier servicio del estado que puede responder: PNP, CEM, Centro de salud, según lugar.
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (538,2,9,12,4,'SUB TOTAL ENTORNO COMUNITARIO LIBRE QUE PROMUEVE EJERCICIO DE DERECHOS', SYSDATE, NULL, 0);
