INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (928,2,10,1,1,'Nombres y apellidos:', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (929,2,10,1,2,'Sexo:', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (930,2,10,1,3,'Dirección:', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (931,2,10,1,4,'Distrito:', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (932,2,10,1,5,'Fecha:', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (933,2,10,2,1,'1. Se toman decisiones para cosas importantes de la familia.', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (934,2,10,2,2,'2. En mi casa predomina la armonía.', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (935,2,10,2,3,'3. En mi casa cada uno cumple con sus responsabilidades.', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (936,2,10,2,4,'4. Las manifestaciones de cariño forman parte de nuestra vida cotidiana', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (937,2,10,2,5,'5. Nos expresamos sin insinuaciones, de forma clara y directa.', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (938,2,10,2,6,'6. Podemos aceptar los defectos de los demás y sobrellevarlos.', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (939,2,10,2,7,'7. Tomamos en consideración las experiencias de otras familias ante situaciones difíciles.', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (940,2,10,2,8,'8. Cuando alguno de la familia tiene un problema, los demás lo ayudan.', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (941,2,10,2,9,'9. Se distribuyen las tareas de forma que nadie esté sobrecargado.', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (942,2,10,2,10,'10. Las costumbres familiares pueden modificarse ante determinadas situaciones.', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (943,2,10,2,11,'11. Podemos conversar diversos temas sin temor.', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (944,2,10,2,12,'12. Ante una situación familiar difícil, somos capaces de buscar ayuda en otras personas.', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (945,2,10,2,13,'13. los intereses y necesidades de cada cual son respetados por el núcleo familiar.', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (946,2,10,2,14,'14. Nos demostramos el cariño que nos tenemos.', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (947,2,10,2,15,'TOTAL', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (948,2,10,3,1,'Diagnóstico de Funcionamiento familiar según puntuación total de la prueba FF-SIL', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (949,2,10,3,2,'¿En qué horarios podría estar disponible para las visitas? (Marcar todas las que considere y/o responda)', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (950,2,11,1,1,'EDAD', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (951,2,11,1,2,'ESTADO CIVIL:', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (952,2,11,1,3,'EDUCACIÓN:', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (953,2,11,2,1,'La mujer cuando sale de casa descuida sus labores en el hogar', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (954,2,11,2,2,'Generalmente las amistades o familiares de la mujer se entrometen en su relación de pareja, poniéndola en contra del esposo o pareja', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (955,2,11,2,3,'La mujer no debe trabajar si su esposo o pareja no quiere que lo haga', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (956,2,11,2,4,'El ingreso económico de varón casado o conviviente y la forma cómo lo gasta, es un asunto privado que solo le incumbe a él', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (957,2,11,2,5,'Algunas veces las mujeres solo entienden con gritos o golpes', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (958,2,11,2,6,'Toda mujer debe cumplir primero con su rol de madre, esposa o ama de casa, y después realizar sus propios sueños', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (959,2,11,2,7,'Desde muy niñas, las mujeres deben aprender a ser pacientes, comprensivas y complacer a sus esposos o parejas en todo', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (960,2,11,2,8,'A las mujeres les corresponde realizar todas las tareas del hogar', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (961,2,11,2,9,'En todo hogar se necesita a un varón para que ponga orden y disciplina', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (962,2,11,2,10,'El esposo o pareja, siempre debe ser el jefe del hogar y quien represente a su familia', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (963,2,11,2,11,'El esposo o pareja, es quien debe tomar las decisiones más importantes en el hogar', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (964,2,11,3,1,'En una discusión de pareja, es normal que el varón como expresión de cólera insulte a su esposa o pareja.', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (965,2,11,3,2,'Si se ve a un varón golpeando a su esposa o pareja, debe ser porque ella hizo algo malo', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (966,2,11,3,3,'El varón tiene derecho a golpear o castigar a su mujer, cuando la situación lo justifica', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (967,2,11,3,4,'Si una mujer le falta de respeto a su esposo o pareja, ella merece alguna forma de castigo', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (968,2,11,3,5,'Si una mujer no atiende a su esposo o pareja o no cumple con sus deberes del hogar, merece ser reprendida por su esposo o pareja', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (969,2,11,3,6,'El varón siempre debe dejar en claro que es él quien manda en la casa', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (970,2,11,3,7,'Aunque haya maltrato, una mujer siempre debe estar con su esposo / pareja', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (971,2,11,3,8,'En ninguna situación la mujer debe contradecir las decisiones de su esposo o pareja', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (972,2,11,3,9,'La mujer siempre debe estar dispuesta a tener relaciones sexuales cuando su esposo o pareja lo desea', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (973,2,11,3,10,'La mujer no puede tomar decisiones sin el permiso de su esposo /pareja', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (974,2,11,3,11,'A fin de evitar discusiones en el hogar, la mujer debería ceder', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (975,2,11,3,12,'La mujer no debe tener amistades que su esposo o pareja no apruebe', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (976,2,11,3,13,'La mujer no debe molestar a su esposo o pareja con preguntas sobre sus ingresos económicos', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (977,2,11,4,1,'A las mujeres que son sumisas les gusta que las traten mal', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (978,2,11,4,2,'El varón es dominante y agresivo por eso trata duramente a la mujer', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (979,2,11,4,3,'El cuerpo de la mujer se puede usar para la publicidad de productos comerciales', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (980,2,11,4,4,'La mujer debe permitir todo lo que su esposo o pareja le pida sexualmente', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (981,2,11,4,5,'Un varón tiene el derecho de usar la fuerza para corregir a su esposa o pareja si ella coquetea con otros varones', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (982,2,11,4,6,'La mujer que es infiel a su esposo o pareja debe tener alguna forma de castigo por él', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (983,2,11,4,7,'Las mujeres que descuiden a sus hijos merecen tener alguna forma de castigo por su esposo o pareja', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (984,2,11,4,8,'El amor y paciencia de la mujer, tarde o temprano hará que su esposo o pareja deje de ser violento', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (985,2,11,4,9,'El varón es violento por naturaleza y por eso no puede cambiar su conducta', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (986,2,11,4,10,'El varón cela a su esposa o pareja porque así le demuestra que la ama', SYSDATE, NULL, 0, NULL);
INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (987,2,11,4,11,'Una mujer que se viste provocativamente está buscando que la acosen sexualmente', SYSDATE, NULL, 0, NULL);
