INSERT INTO SSI_ANEXOS_PREGUNTAS VALUES (1359,2,27,2,3,'3. A través de la estrategia "Con Punche Familias", vengo recibiendo de manera regular, sesiones de consejería en mi domicilio o por teleasistencia, por parte de los/ las acompañantes familiares del INABIF.', SYSDATE, NULL, 0, NULL,'Totalmente en desacuerdo | En desacuerdo | Indecisa/o | De acuerdo | Totalmente de  cuerdo','select',-1,-1);
