SELECT * FROM SSI_ANEXO_FORMULARIO_RESPUESTA p
/

SELECT * FROM SSI_ANEXOS_RESPUESTAS p
/

SELECT * FROM SSI_POTENCIALES_FAMILIAS p
WHERE 
   p.SI_ID_SERVICIO = 2
ORDER BY p.PF_ID_FAMILIA DESC
/

SELECT * FROM SSI_ANEXOS_PREGUNTAS p
WHERE
   p.SI_ID_SERVICIO = 2
   AND p.AP_NUM_ANEXO = 9
   AND p.AP_NUM_GRUPO = -4
ORDER BY p.AP_ID_PREGUNTA DESC
/

